export function groupRecognitionResultsByLine(recognition){let result={text:"",lines:[],confidence:0};if(!recognition.length){return result}let totalConfidence=recognition.reduce((sum,r)=>sum+r.confidence,0);result.confidence=totalConfidence/recognition.length;let firstRec=recognition[0];if(!firstRec)return result;let currentLine=[firstRec];let fullText=firstRec.text;let avgHeight=firstRec.box.height;for(let i=1;i<recognition.length;i++){let current=recognition[i];let previous=recognition[i-1];if(!current||!previous)continue;let verticalGap=Math.abs(current.box.y-previous.box.y);let threshold=avgHeight*0.5;if(verticalGap<=threshold){currentLine.push(current);fullText+=` ${current.text}`;avgHeight=currentLine.reduce((sum,r)=>sum+r.box.height,0)/currentLine.length}else{result.lines.push([...currentLine]);fullText+=`
${current.text}`;currentLine=[current];avgHeight=current.box.height}}if(currentLine.length>0){result.lines.push([...currentLine])}result.text=fullText;return result}